INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חיפוי קירות וקרמיקה', '**חיפוי קיר לא צמוד / בולט** — אריח חיפוי קיר שלא צמוד למשטח — בולט או מתנדנד.. המלצה: הסרת אריח, ניקוי, הדבקה מחדש. עלות משוערת: ₪200-₪450 (ליחידה)', '**חיפוי קיר לא צמוד / בולט** — אריח חיפוי קיר שלא צמוד למשטח — בולט או מתנדנד.. המלצה: הסרת אריח, ניקוי, הדבקה מחדש. עלות משוערת: ₪200-₪450 (ליחידה)', 'ת"י 1555 — חיפוי קירות חייב להיות צמוד לבסיס במלואו', 'ת"י 1555 — חיפוי קירות חייב להיות צמוד לבסיס במלואו', true, 'medium');
