INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'גבס', '**לוח גבס עם כתמי רטיבות** — כתמי רטיבות על לוח גבס, לרוב בתקרה או בקירות חדרים רטובים. לוח גבס רגיל (לבן) שהותקן באזור רטוב במקום לוח ירוק עמיד מים.. המלצה: החלפת הלוח הפגום בלוח גבס ירוק (עמיד מים), טיפול במקור הרטיבות, שפכטל וצביעה. עלות משוערת: ₪200-₪500 (למ"ר)', '**לוח גבס עם כתמי רטיבות** — כתמי רטיבות על לוח גבס, לרוב בתקרה או בקירות חדרים רטובים. לוח גבס רגיל (לבן) שהותקן באזור רטוב במקום לוח ירוק עמיד מים.. המלצה: החלפת הלוח הפגום בלוח גבס ירוק (עמיד מים), טיפול במקור הרטיבות, שפכטל וצביעה. עלות משוערת: ₪200-₪500 (למ"ר)', 'ת"י 4283 — באזורים רטובים (חדרי אמבטיה, מטבחים) יש להשתמש בלוחות גבס עמידים ברטיבות (ירוקים)', 'ת"י 4283 — באזורים רטובים (חדרי אמבטיה, מטבחים) יש להשתמש בלוחות גבס עמידים ברטיבות (ירוקים)', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'גבס', '**סדק בתפר בין לוחות גבס** — סדק לאורך התפר בין שני לוחות גבס. נגרם לרוב מטיפול לא נכון בתפר — חוסר בסרט תפר או שימוש בשפכטל לא מתאים.. המלצה: פתיחת הסדק, הדבקת סרט רשת פיברגלס, שפכטל בשלוש שכבות עם ליטוש בין שכבה לשכבה. עלות משוערת: ₪40-₪80 (למ"א)', '**סדק בתפר בין לוחות גבס** — סדק לאורך התפר בין שני לוחות גבס. נגרם לרוב מטיפול לא נכון בתפר — חוסר בסרט תפר או שימוש בשפכטל לא מתאים.. המלצה: פתיחת הסדק, הדבקת סרט רשת פיברגלס, שפכטל בשלוש שכבות עם ליטוש בין שכבה לשכבה. עלות משוערת: ₪40-₪80 (למ"א)', 'ת"י 4283 — תפרים בין לוחות גבס חייבים להיות מטופלים בסרט תפר ושפכטל מתאים למניעת סדקים', 'ת"י 4283 — תפרים בין לוחות גבס חייבים להיות מטופלים בסרט תפר ושפכטל מתאים למניעת סדקים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'גבס', '**בליטת ברגים בלוח גבס** — ראשי הברגים בולטים מעבר לפני השטח של לוח הגבס ולא שוקעו כראוי. נראים כנקודות בולטות לאחר הצביעה.. המלצה: שקיעת הברגים הבולטים, כיסוי בשפכטל בשתי שכבות, ליטוש וצביעה. עלות משוערת: ₪20-₪50 (ליחידה)', '**בליטת ברגים בלוח גבס** — ראשי הברגים בולטים מעבר לפני השטח של לוח הגבס ולא שוקעו כראוי. נראים כנקודות בולטות לאחר הצביעה.. המלצה: שקיעת הברגים הבולטים, כיסוי בשפכטל בשתי שכבות, ליטוש וצביעה. עלות משוערת: ₪20-₪50 (ליחידה)', 'ת"י 4283 — ברגים חייבים להיות משוקעים 1-2 מ"מ מתחת לפני השטח ומכוסים בשפכטל', 'ת"י 4283 — ברגים חייבים להיות משוקעים 1-2 מ"מ מתחת לפני השטח ומכוסים בשפכטל', true, 'low');
