INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'גבס', '**הפרש גובה בין לוח גבס לקיר טיח** — הפרש גובה (מדרגה) במעבר בין תקרת/קיר גבס לקיר טיח. גורם לבעיה אסתטית ומקשה על צביעה אחידה.. המלצה: יישור האזור באמצעות שפכטל, שימוש בפרופיל מעבר מתאים, ליטוש וצביעה. עלות משוערת: ₪30-₪60 (למ"א)', '**הפרש גובה בין לוח גבס לקיר טיח** — הפרש גובה (מדרגה) במעבר בין תקרת/קיר גבס לקיר טיח. גורם לבעיה אסתטית ומקשה על צביעה אחידה.. המלצה: יישור האזור באמצעות שפכטל, שימוש בפרופיל מעבר מתאים, ליטוש וצביעה. עלות משוערת: ₪30-₪60 (למ"א)', 'ת"י 4283 — מעבר בין לוח גבס לטיח חייב להיות חלק וללא מדרגה', 'ת"י 4283 — מעבר בין לוח גבס לטיח חייב להיות חלק וללא מדרגה', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'גבס', '**שפכטל לא מוחלק — טקסטורה גסה** — עבודת השפכטל על לוחות הגבס לא הושלמה כראוי — ניתן לראות קווי שפכטל, סימני כלי עבודה, או טקסטורה לא אחידה שבולטת לאחר הצביעה.. המלצה: ליטוש מחדש של כל המשטח בנייר שיוף עדין (220-320), שכבת שפכטל סופית, ליטוש נוסף. עלות משוערת: ₪30-₪60 (למ"ר)', '**שפכטל לא מוחלק — טקסטורה גסה** — עבודת השפכטל על לוחות הגבס לא הושלמה כראוי — ניתן לראות קווי שפכטל, סימני כלי עבודה, או טקסטורה לא אחידה שבולטת לאחר הצביעה.. המלצה: ליטוש מחדש של כל המשטח בנייר שיוף עדין (220-320), שכבת שפכטל סופית, ליטוש נוסף. עלות משוערת: ₪30-₪60 (למ"ר)', 'ת"י 4283 — גימור שפכטל חייב להיות חלק ואחיד ללא סימני כלי עבודה', 'ת"י 4283 — גימור שפכטל חייב להיות חלק ואחיד ללא סימני כלי עבודה', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'גבס', '**גבס קרטון ללא בידוד אקוסטי מספיק** — מחיצת גבס קרטון בין דירות או חדרים שאינה עומדת בדרישות הבידוד האקוסטי. ניתן לשמוע רעשים מהצד השני.. המלצה: הוספת שכבת בידוד (צמר סלעים) בתוך המחיצה, או הוספת לוח גבס נוסף עם שכבת דמפינג. עלות משוערת: ₪150-₪350 (למ"ר)', '**גבס קרטון ללא בידוד אקוסטי מספיק** — מחיצת גבס קרטון בין דירות או חדרים שאינה עומדת בדרישות הבידוד האקוסטי. ניתן לשמוע רעשים מהצד השני.. המלצה: הוספת שכבת בידוד (צמר סלעים) בתוך המחיצה, או הוספת לוח גבס נוסף עם שכבת דמפינג. עלות משוערת: ₪150-₪350 (למ"ר)', 'ת"י 1419 — מחיצת גבס בין דירות חייבת לעמוד בערך בידוד אקוסטי מינימלי של Rw=50dB', 'ת"י 1419 — מחיצת גבס בין דירות חייבת לעמוד בערך בידוד אקוסטי מינימלי של Rw=50dB', true, 'medium');
