INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אבן ושיש', '**אבן חיפוי חיצוני רופפת** — אבן חיפוי חיצונית שאינה מחוברת היטב למבנה ונעה בלחיצה. מהווה סכנת נפילה חמורה, במיוחד בקומות גבוהות.. המלצה: הסרה מבוקרת של האבן, בדיקת העיגון המכני, הדבקה מחדש עם דבק C2S1 ועיגון מכני נוסף. עלות משוערת: ₪300-₪800 (למ"ר)', '**אבן חיפוי חיצוני רופפת** — אבן חיפוי חיצונית שאינה מחוברת היטב למבנה ונעה בלחיצה. מהווה סכנת נפילה חמורה, במיוחד בקומות גבוהות.. המלצה: הסרה מבוקרת של האבן, בדיקת העיגון המכני, הדבקה מחדש עם דבק C2S1 ועיגון מכני נוסף. עלות משוערת: ₪300-₪800 (למ"ר)', 'ת"י 2378 — אבן חיפוי חיצונית חייבת להיות מעוגנת מכנית בנוסף להדבקה, בהתאם לגובה ולמשקל', 'ת"י 2378 — אבן חיפוי חיצונית חייבת להיות מעוגנת מכנית בנוסף להדבקה, בהתאם לגובה ולמשקל', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אבן ושיש', '**סדק באבן חיפוי** — סדק באבן חיפוי חיצונית או פנימית. עלול להיגרם מתזוזות תרמיות, מתח מכני, או פגם באבן עצמה.. המלצה: החלפת האבן הסדוקה באבן חדשה מאותו המחצבה ועם גימור זהה. עלות משוערת: ₪250-₪700 (ליחידה)', '**סדק באבן חיפוי** — סדק באבן חיפוי חיצונית או פנימית. עלול להיגרם מתזוזות תרמיות, מתח מכני, או פגם באבן עצמה.. המלצה: החלפת האבן הסדוקה באבן חדשה מאותו המחצבה ועם גימור זהה. עלות משוערת: ₪250-₪700 (ליחידה)', 'ת"י 2378 — אבני חיפוי חייבות להיות שלמות וללא סדקים הפוגעים ביציבותן', 'ת"י 2378 — אבני חיפוי חייבות להיות שלמות וללא סדקים הפוגעים ביציבותן', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אבן ושיש', '**כתמים על אבן טבעית** — כתמים על משטח אבן טבעית (שיש, גרניט) כתוצאה מחומרי ניקוי לא מתאימים, דבק שחלחל, או חומרי בנייה שנשפכו.. המלצה: ניקוי מקצועי באמצעות חומרים ייעודיים לאבן טבעית, ליטוש מקומי במידת הצורך, יישום חומר הגנה. עלות משוערת: ₪50-₪150 (למ"ר)', '**כתמים על אבן טבעית** — כתמים על משטח אבן טבעית (שיש, גרניט) כתוצאה מחומרי ניקוי לא מתאימים, דבק שחלחל, או חומרי בנייה שנשפכו.. המלצה: ניקוי מקצועי באמצעות חומרים ייעודיים לאבן טבעית, ליטוש מקומי במידת הצורך, יישום חומר הגנה. עלות משוערת: ₪50-₪150 (למ"ר)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אבן ושיש', '**חוסר עיגון מכני באבן חיפוי בגובה** — אבן חיפוי בגובה מעל 4 מטר שהודבקה ללא עיגון מכני נוסף. מהווה סכנת נפילה חמורה ודורש טיפול מיידי.. המלצה: הוספת עיגון מכני (סיכות נירוסטה או מסגרת תלייה) לכל אבני החיפוי מעל 4 מ''. עלות משוערת: ₪200-₪600 (למ"ר)', '**חוסר עיגון מכני באבן חיפוי בגובה** — אבן חיפוי בגובה מעל 4 מטר שהודבקה ללא עיגון מכני נוסף. מהווה סכנת נפילה חמורה ודורש טיפול מיידי.. המלצה: הוספת עיגון מכני (סיכות נירוסטה או מסגרת תלייה) לכל אבני החיפוי מעל 4 מ''. עלות משוערת: ₪200-₪600 (למ"ר)', 'ת"י 2378 — אבן חיפוי בגובה מעל 4 מ'' חייבת לכלול עיגון מכני בנוסף להדבקה כימית', 'ת"י 2378 — אבן חיפוי בגובה מעל 4 מ'' חייבת לכלול עיגון מכני בנוסף להדבקה כימית', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אבן ושיש', '**רובה חסרה בין אבני חיפוי** — חוסר ברובה (מילוי) בין אבני החיפוי החיצוני. מאפשר חדירת מים מאחורי האבנים ועלול לגרום לנזק מצטבר ולניתוק.. המלצה: מילוי התפרים בחומר איטום פוליאורתני או סיליקון בצבע מתאים לאבן. עלות משוערת: ₪40-₪80 (למ"א)', '**רובה חסרה בין אבני חיפוי** — חוסר ברובה (מילוי) בין אבני החיפוי החיצוני. מאפשר חדירת מים מאחורי האבנים ועלול לגרום לנזק מצטבר ולניתוק.. המלצה: מילוי התפרים בחומר איטום פוליאורתני או סיליקון בצבע מתאים לאבן. עלות משוערת: ₪40-₪80 (למ"א)', 'ת"י 2378 — תפרים בין אבני חיפוי חיצוני חייבים להיות ממולאים בחומר איטום גמיש', 'ת"י 2378 — תפרים בין אבני חיפוי חיצוני חייבים להיות ממולאים בחומר איטום גמיש', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אבן ושיש', '**אדן שיש/אבן סדוק** — סדק באדן חלון או משטח עבודה מאבן טבעית. לרוב נגרם ממתח מכני, תזוזת מבנה, או חיתוך לקוי של האבן.. המלצה: תיקון בשרף אפוקסי שקוף או בצבע מתאים, ליטוש מקומי. במקרים חמורים — החלפת האבן. עלות משוערת: ₪200-₪600 (ליחידה)', '**אדן שיש/אבן סדוק** — סדק באדן חלון או משטח עבודה מאבן טבעית. לרוב נגרם ממתח מכני, תזוזת מבנה, או חיתוך לקוי של האבן.. המלצה: תיקון בשרף אפוקסי שקוף או בצבע מתאים, ליטוש מקומי. במקרים חמורים — החלפת האבן. עלות משוערת: ₪200-₪600 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אבן ושיש', '**חוסר נוטפים באדן אבן חיצוני** — אדן אבן חיצוני ללא חריץ נוטפים בתחתיתו, מה שגורם למים לזרום לאורך הקיר ולגרום לכתמי רטיבות ונזק.. המלצה: חריצת חריץ נוטפים בתחתית האדן באמצעות מסור יהלום, או החלפת האדן. עלות משוערת: ₪100-₪250 (ליחידה)', '**חוסר נוטפים באדן אבן חיצוני** — אדן אבן חיצוני ללא חריץ נוטפים בתחתיתו, מה שגורם למים לזרום לאורך הקיר ולגרום לכתמי רטיבות ונזק.. המלצה: חריצת חריץ נוטפים בתחתית האדן באמצעות מסור יהלום, או החלפת האדן. עלות משוערת: ₪100-₪250 (ליחידה)', 'ת"י 2378 — אדני חלון חיצוניים מאבן חייבים לכלול חריץ נוטפים בתחתיתם', 'ת"י 2378 — אדני חלון חיצוניים מאבן חייבים לכלול חריץ נוטפים בתחתיתם', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אבן ושיש', '**חללים מתחת לאבן שיש מדרגות** — אבני שיש במדרגות עם חללים מתחתיהן. גורם לרעש (צליל חלול בהליכה) ולסיכון לשבירת האבן תחת עומס.. המלצה: הזרקת דבק אפוקסי דרך קידוחים קטנים למילוי החללים, או פירוק והדבקה מחדש. עלות משוערת: ₪200-₪500 (למ"א)', '**חללים מתחת לאבן שיש מדרגות** — אבני שיש במדרגות עם חללים מתחתיהן. גורם לרעש (צליל חלול בהליכה) ולסיכון לשבירת האבן תחת עומס.. המלצה: הזרקת דבק אפוקסי דרך קידוחים קטנים למילוי החללים, או פירוק והדבקה מחדש. עלות משוערת: ₪200-₪500 (למ"א)', 'ת"י 2378 — אבן מדרגות חייבת להיות מודבקת על כיסוי דבק מלא (100%) ללא חללים', 'ת"י 2378 — אבן מדרגות חייבת להיות מודבקת על כיסוי דבק מלא (100%) ללא חללים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אבן ושיש', '**אף מדרגה אבן בולט או חד** — אף (קצה) מדרגת אבן שאינו מעובד כראוי — חד, בולט, או לא מעוגל. מהווה סכנת מעידה ופציעה.. המלצה: עיגול או שיפוע קצה המדרגה באמצעות ליטוש מקצועי, או התקנת פרופיל אף מדרגה. עלות משוערת: ₪60-₪150 (למ"א)', '**אף מדרגה אבן בולט או חד** — אף (קצה) מדרגת אבן שאינו מעובד כראוי — חד, בולט, או לא מעוגל. מהווה סכנת מעידה ופציעה.. המלצה: עיגול או שיפוע קצה המדרגה באמצעות ליטוש מקצועי, או התקנת פרופיל אף מדרגה. עלות משוערת: ₪60-₪150 (למ"א)', 'ת"י 2378 — אף מדרגה חייב להיות מעוגל או משופע למניעת סכנת מעידה', 'ת"י 2378 — אף מדרגה חייב להיות מעוגל או משופע למניעת סכנת מעידה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אבן ושיש', '**אבן משתלבת (חיצוני) שוקעת או בולטת** — אבני משתלבות בחניה או בשביל גישה שאינן במפלס אחיד — חלקן שוקעות וחלקן בולטות. מעיד על תשתית חול לא מהודקת.. המלצה: הרמת האבנים באזור הבעייתי, השלמת והידוק שכבת החול, הנחה מחדש עם הידוק. עלות משוערת: ₪40-₪80 (למ"ר)', '**אבן משתלבת (חיצוני) שוקעת או בולטת** — אבני משתלבות בחניה או בשביל גישה שאינן במפלס אחיד — חלקן שוקעות וחלקן בולטות. מעיד על תשתית חול לא מהודקת.. המלצה: הרמת האבנים באזור הבעייתי, השלמת והידוק שכבת החול, הנחה מחדש עם הידוק. עלות משוערת: ₪40-₪80 (למ"ר)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**נזילה מצנרת אספקת מים קרים** — נזילת מים מצנרת אספקת מים קרים בנקודות חיבור או לאורך הצנרת. עלולה לגרום לנזקי רטיבות בקירות ובתקרות, ולהתפתחות עובש.. המלצה: לאתר את מקור הנזילה, לנתק את אספקת המים, לתקן או להחליף את הקטע הפגום ולבצע בדיקת לחץ חוזרת.. עלות משוערת: ₪300-₪1200 (ליחידה)', '**נזילה מצנרת אספקת מים קרים** — נזילת מים מצנרת אספקת מים קרים בנקודות חיבור או לאורך הצנרת. עלולה לגרום לנזקי רטיבות בקירות ובתקרות, ולהתפתחות עובש.. המלצה: לאתר את מקור הנזילה, לנתק את אספקת המים, לתקן או להחליף את הקטע הפגום ולבצע בדיקת לחץ חוזרת.. עלות משוערת: ₪300-₪1200 (ליחידה)', 'ת"י 1205 חלק 1 — מערכת אספקת המים חייבת לעמוד בבדיקת לחץ של 1.5 פעמים מלחץ העבודה המרבי, ולא פחות מ-10 אטמוספרות, למשך שעתיים ללא ירידת לחץ.', 'ת"י 1205 חלק 1 — מערכת אספקת המים חייבת לעמוד בבדיקת לחץ של 1.5 פעמים מלחץ העבודה המרבי, ולא פחות מ-10 אטמוספרות, למשך שעתיים ללא ירידת לחץ.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**נזילה מצנרת אספקת מים חמים** — נזילת מים מצנרת אספקת מים חמים. נזילה ממערכת מים חמים חמורה יותר בשל הסיכון לכוויות ונזק מואץ לחומרי בניין.. המלצה: לאתר את מקור הנזילה, לתקן או להחליף את הקטע הפגום, לבדוק תקינות בידוד תרמי של הצנרת, ולבצע בדיקת לחץ.. עלות משוערת: ₪400-₪1500 (ליחידה)', '**נזילה מצנרת אספקת מים חמים** — נזילת מים מצנרת אספקת מים חמים. נזילה ממערכת מים חמים חמורה יותר בשל הסיכון לכוויות ונזק מואץ לחומרי בניין.. המלצה: לאתר את מקור הנזילה, לתקן או להחליף את הקטע הפגום, לבדוק תקינות בידוד תרמי של הצנרת, ולבצע בדיקת לחץ.. עלות משוערת: ₪400-₪1500 (ליחידה)', 'ת"י 1205 חלק 1 — צנרת מים חמים חייבת לעמוד בבדיקת לחץ זהה לצנרת מים קרים, ובנוסף לעמוד בטמפרטורות עבודה עד 80°C.', 'ת"י 1205 חלק 1 — צנרת מים חמים חייבת לעמוד בבדיקת לחץ זהה לצנרת מים קרים, ובנוסף לעמוד בטמפרטורות עבודה עד 80°C.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**לחץ מים נמוך מהנדרש** — לחץ המים בנקודות הקצה (ברזים, מקלחות) נמוך מהנדרש בתקן. גורם לזרימה חלשה ולתפקוד לקוי של מערכות כגון מקלחות ומדיחי כלים.. המלצה: לבדוק את קוטר הצנרת, לוודא היעדר חסימות, לבדוק תקינות משאבת לחץ (אם קיימת), ובמידת הצורך להתקין משאבת הגברת לחץ.. עלות משוערת: ₪500-₪3000 (ליחידה)', '**לחץ מים נמוך מהנדרש** — לחץ המים בנקודות הקצה (ברזים, מקלחות) נמוך מהנדרש בתקן. גורם לזרימה חלשה ולתפקוד לקוי של מערכות כגון מקלחות ומדיחי כלים.. המלצה: לבדוק את קוטר הצנרת, לוודא היעדר חסימות, לבדוק תקינות משאבת לחץ (אם קיימת), ובמידת הצורך להתקין משאבת הגברת לחץ.. עלות משוערת: ₪500-₪3000 (ליחידה)', 'ת"י 1205 חלק 1 — לחץ המים המינימלי בנקודת הצריכה הרחוקה ביותר לא יפחת מ-1 אטמוספרה (0.1 מגה-פסקל). לחץ מרבי לא יעלה על 5 אטמוספרות.', 'ת"י 1205 חלק 1 — לחץ המים המינימלי בנקודת הצריכה הרחוקה ביותר לא יפחת מ-1 אטמוספרה (0.1 מגה-פסקל). לחץ מרבי לא יעלה על 5 אטמוספרות.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**היעדר מפסק מים ראשי או שסתום ניתוק** — לא הותקן שסתום ניתוק (ברז ראשי) בכניסת אספקת המים לדירה, או שהשסתום אינו נגיש או אינו תקין.. המלצה: להתקין שסתום כדורי בכניסת המים לדירה, במקום נגיש ומסומן.. עלות משוערת: ₪200-₪600 (ליחידה)', '**היעדר מפסק מים ראשי או שסתום ניתוק** — לא הותקן שסתום ניתוק (ברז ראשי) בכניסת אספקת המים לדירה, או שהשסתום אינו נגיש או אינו תקין.. המלצה: להתקין שסתום כדורי בכניסת המים לדירה, במקום נגיש ומסומן.. עלות משוערת: ₪200-₪600 (ליחידה)', 'ת"י 1205 חלק 1 — יש להתקין שסתום ניתוק בכניסת המים לכל יחידת דיור, במקום נגיש, המאפשר סגירה מלאה של אספקת המים.', 'ת"י 1205 חלק 1 — יש להתקין שסתום ניתוק בכניסת המים לכל יחידת דיור, במקום נגיש, המאפשר סגירה מלאה של אספקת המים.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**היעדר מפסק מים נקודתי לכלי סניטרי** — חסר שסתום ניתוק נקודתי (אנגל) בחיבור לכלי סניטרי (אסלה, כיור, מכונת כביסה). לא ניתן לסגור מים לכלי ספציפי ללא ניתוק כל הדירה.. המלצה: להתקין ברז אנגל לכל כלי סניטרי בהתאם לתקן.. עלות משוערת: ₪150-₪350 (ליחידה)', '**היעדר מפסק מים נקודתי לכלי סניטרי** — חסר שסתום ניתוק נקודתי (אנגל) בחיבור לכלי סניטרי (אסלה, כיור, מכונת כביסה). לא ניתן לסגור מים לכלי ספציפי ללא ניתוק כל הדירה.. המלצה: להתקין ברז אנגל לכל כלי סניטרי בהתאם לתקן.. עלות משוערת: ₪150-₪350 (ליחידה)', 'ת"י 1205 חלק 1 — יש להתקין שסתום ניתוק נפרד לכל כלי סניטרי לצורך תחזוקה ותיקון.', 'ת"י 1205 חלק 1 — יש להתקין שסתום ניתוק נפרד לכל כלי סניטרי לצורך תחזוקה ותיקון.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**רעש מצנרת – פטישי מים (water hammer)** — רעשי חבטות או רעידות בצנרת בעת סגירת ברזים או שסתומים. תופעת פטישי מים (water hammer) הנגרמת מעצירה פתאומית של זרימה.. המלצה: להתקין בולמי זעזועים (water hammer arrestors) בנקודות הקצה, לבדוק קיבוע צנרת ולהוסיף תופסני צנרת.. עלות משוערת: ₪200-₪800 (ליחידה)', '**רעש מצנרת – פטישי מים (water hammer)** — רעשי חבטות או רעידות בצנרת בעת סגירת ברזים או שסתומים. תופעת פטישי מים (water hammer) הנגרמת מעצירה פתאומית של זרימה.. המלצה: להתקין בולמי זעזועים (water hammer arrestors) בנקודות הקצה, לבדוק קיבוע צנרת ולהוסיף תופסני צנרת.. עלות משוערת: ₪200-₪800 (ליחידה)', 'ת"י 1205 חלק 1 — יש למנוע תופעת פטישי מים באמצעות התקנת בולמי זעזועים (water hammer arrestors) או האטת הסגירה.', 'ת"י 1205 חלק 1 — יש למנוע תופעת פטישי מים באמצעות התקנת בולמי זעזועים (water hammer arrestors) או האטת הסגירה.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**צנרת לא מקובעת – חסרים תופסנים** — צנרת מים או ביוב שאינה מקובעת כראוי לקיר או לתקרה באמצעות תופסנים, גורמת לרעשים, רעידות ועלולה להיסדק.. המלצה: להתקין תופסני צנרת (pipe clamps) בהתאם לתקן, במרווחים הנדרשים ועם בידוד אקוסטי.. עלות משוערת: ₪150-₪500 (ליחידה)', '**צנרת לא מקובעת – חסרים תופסנים** — צנרת מים או ביוב שאינה מקובעת כראוי לקיר או לתקרה באמצעות תופסנים, גורמת לרעשים, רעידות ועלולה להיסדק.. המלצה: להתקין תופסני צנרת (pipe clamps) בהתאם לתקן, במרווחים הנדרשים ועם בידוד אקוסטי.. עלות משוערת: ₪150-₪500 (ליחידה)', 'ת"י 1205 חלק 1 — צנרת תקובע לאלמנטים קשיחים במבנה באמצעות תופסנים מתאימים, במרווחים שלא יעלו על 1.5 מ'' לצנרת אופקית ו-2 מ'' לצנרת אנכית.', 'ת"י 1205 חלק 1 — צנרת תקובע לאלמנטים קשיחים במבנה באמצעות תופסנים מתאימים, במרווחים שלא יעלו על 1.5 מ'' לצנרת אופקית ו-2 מ'' לצנרת אנכית.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**היעדר בידוד תרמי לצנרת מים חמים** — צנרת מים חמים ללא בידוד תרמי (כיסוי מבודד), גורם לאיבוד חום, בזבוז אנרגיה, ועלול לגרום לעיבוי על הצנרת.. המלצה: לעטוף את צנרת המים החמים בבידוד תרמי (שרוול מבודד) בעובי הנדרש לפי קוטר הצנרת.. עלות משוערת: ₪30-₪80 (למ"א)', '**היעדר בידוד תרמי לצנרת מים חמים** — צנרת מים חמים ללא בידוד תרמי (כיסוי מבודד), גורם לאיבוד חום, בזבוז אנרגיה, ועלול לגרום לעיבוי על הצנרת.. המלצה: לעטוף את צנרת המים החמים בבידוד תרמי (שרוול מבודד) בעובי הנדרש לפי קוטר הצנרת.. עלות משוערת: ₪30-₪80 (למ"א)', 'ת"י 1205 חלק 1 — צנרת מים חמים חייבת בבידוד תרמי בעובי מינימלי בהתאם לקוטר הצנרת, למניעת איבוד חום.', 'ת"י 1205 חלק 1 — צנרת מים חמים חייבת בבידוד תרמי בעובי מינימלי בהתאם לקוטר הצנרת, למניעת איבוד חום.', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**דוד שמש – נזילה או התקנה לקויה** — נזילה מדוד השמש, מצנרת העלייה/ירידה לקולטים, או התקנה שאינה עומדת בדרישות התקן (חוסר שסתום ביטחון, חוסר אוורור).. המלצה: לתקן את הנזילה, להתקין שסתומי ביטחון חסרים, לבדוק תקינות הצנרת מהקולטים לדוד ובחזרה.. עלות משוערת: ₪400-₪2000 (ליחידה)', '**דוד שמש – נזילה או התקנה לקויה** — נזילה מדוד השמש, מצנרת העלייה/ירידה לקולטים, או התקנה שאינה עומדת בדרישות התקן (חוסר שסתום ביטחון, חוסר אוורור).. המלצה: לתקן את הנזילה, להתקין שסתומי ביטחון חסרים, לבדוק תקינות הצנרת מהקולטים לדוד ובחזרה.. עלות משוערת: ₪400-₪2000 (ליחידה)', 'ת"י 579 — דוד שמש יותקן עם שסתום ביטחון (שסתום לחץ), שסתום חד-כיווני, ומערכת ניקוז לעודפי לחץ. חיבור לפי הוראות היצרן.', 'ת"י 579 — דוד שמש יותקן עם שסתום ביטחון (שסתום לחץ), שסתום חד-כיווני, ומערכת ניקוז לעודפי לחץ. חיבור לפי הוראות היצרן.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**חימום מים חשמלי (בויילר) – היעדר שסתום ביטחון** — מחמם מים חשמלי (בויילר) מותקן ללא שסתום ביטחון (שסתום לחץ ותרמוסטטי), מהווה סכנת פיצוץ.. המלצה: להתקין שסתום ביטחון (T&P valve) תקני, עם צנרת ניקוז לרצפה או לנקודת ניקוז בטוחה.. עלות משוערת: ₪200-₪500 (ליחידה)', '**חימום מים חשמלי (בויילר) – היעדר שסתום ביטחון** — מחמם מים חשמלי (בויילר) מותקן ללא שסתום ביטחון (שסתום לחץ ותרמוסטטי), מהווה סכנת פיצוץ.. המלצה: להתקין שסתום ביטחון (T&P valve) תקני, עם צנרת ניקוז לרצפה או לנקודת ניקוז בטוחה.. עלות משוערת: ₪200-₪500 (ליחידה)', 'ת"י 1596 — חובה להתקין שסתום ביטחון על כל מחמם מים חשמלי, המשחרר לחץ עודף בלחץ של 6 אטמוספרות ובטמפרטורה של 93°C.', 'ת"י 1596 — חובה להתקין שסתום ביטחון על כל מחמם מים חשמלי, המשחרר לחץ עודף בלחץ של 6 אטמוספרות ובטמפרטורה של 93°C.', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**מחמם מים (בויילר) – התקנה לא בטוחה** — בויילר מותקן באופן לא בטוח – ללא עיגון תקני לקיר, ללא מגש איסוף נזילות, או בסמיכות למתקנים חשמליים.. המלצה: לעגן את הבויילר בבורגי הרחבה מתאימים לקיר, להתקין מגש איסוף עם ניקוז, ולוודא מרחק מספיק ממתקנים חשמליים.. עלות משוערת: ₪300-₪800 (ליחידה)', '**מחמם מים (בויילר) – התקנה לא בטוחה** — בויילר מותקן באופן לא בטוח – ללא עיגון תקני לקיר, ללא מגש איסוף נזילות, או בסמיכות למתקנים חשמליים.. המלצה: לעגן את הבויילר בבורגי הרחבה מתאימים לקיר, להתקין מגש איסוף עם ניקוז, ולוודא מרחק מספיק ממתקנים חשמליים.. עלות משוערת: ₪300-₪800 (ליחידה)', 'ת"י 1596 — מחמם מים יותקן על קיר חזק מספיק לשאת את משקלו המלא, עם עיגון מתאים, ומגש ניקוז מתחתיו.', 'ת"י 1596 — מחמם מים יותקן על קיר חזק מספיק לשאת את משקלו המלא, עם עיגון מתאים, ומגש ניקוז מתחתיו.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**מד מים – נזילה או התקנה לקויה** — נזילה ממד המים הדירתי, התקנה לא תקינה, או חוסר נגישות למד המים.. המלצה: לתקן את הנזילה, לוודא שסתומי ניתוק תקינים, ולהבטיח נגישות למד המים.. עלות משוערת: ₪200-₪700 (ליחידה)', '**מד מים – נזילה או התקנה לקויה** — נזילה ממד המים הדירתי, התקנה לא תקינה, או חוסר נגישות למד המים.. המלצה: לתקן את הנזילה, לוודא שסתומי ניתוק תקינים, ולהבטיח נגישות למד המים.. עלות משוערת: ₪200-₪700 (ליחידה)', 'ת"י 1205 חלק 1 — מד מים יותקן במקום נגיש לקריאה ותחזוקה, עם שסתומי ניתוק משני צידיו.', 'ת"י 1205 חלק 1 — מד מים יותקן במקום נגיש לקריאה ותחזוקה, עם שסתומי ניתוק משני צידיו.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**היעדר מניעת זרימה חוזרת (backflow prevention)** — חסר מתקן למניעת זרימה חוזרת (שסתום חד-כיווני) במערכת אספקת המים, מהווה סיכון בריאותי של זיהום מי השתייה.. המלצה: להתקין שסתום חד-כיווני (check valve) או מפריד ואקום בנקודות הנדרשות.. עלות משוערת: ₪200-₪600 (ליחידה)', '**היעדר מניעת זרימה חוזרת (backflow prevention)** — חסר מתקן למניעת זרימה חוזרת (שסתום חד-כיווני) במערכת אספקת המים, מהווה סיכון בריאותי של זיהום מי השתייה.. המלצה: להתקין שסתום חד-כיווני (check valve) או מפריד ואקום בנקודות הנדרשות.. עלות משוערת: ₪200-₪600 (ליחידה)', 'ת"י 1205 חלק 1 — יש להתקין אמצעי למניעת זרימה חוזרת בכל נקודת חיבור שקיים בה סיכון לזיהום מי השתייה (הפרש גובה מינימלי או שסתום).', 'ת"י 1205 חלק 1 — יש להתקין אמצעי למניעת זרימה חוזרת בכל נקודת חיבור שקיים בה סיכון לזיהום מי השתייה (הפרש גובה מינימלי או שסתום).', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**צנרת מים חוצה קיר ללא אטימה** — צנרת מים העוברת דרך קיר או רצפה ללא שרוול מגן (sleeve) ואטימה מתאימה, מאפשרת מעבר מים ולחות.. המלצה: להתקין שרוול מגן (sleeve) ולאטום את המרווח בחומר איטום גמיש.. עלות משוערת: ₪100-₪400 (ליחידה)', '**צנרת מים חוצה קיר ללא אטימה** — צנרת מים העוברת דרך קיר או רצפה ללא שרוול מגן (sleeve) ואטימה מתאימה, מאפשרת מעבר מים ולחות.. המלצה: להתקין שרוול מגן (sleeve) ולאטום את המרווח בחומר איטום גמיש.. עלות משוערת: ₪100-₪400 (ליחידה)', 'ת"י 1205 חלק 1 — צנרת העוברת דרך קיר או רצפה תוחדר בתוך שרוול מגן, והמרווח ביניהם יאטם בחומר גמיש.', 'ת"י 1205 חלק 1 — צנרת העוברת דרך קיר או רצפה תוחדר בתוך שרוול מגן, והמרווח ביניהם יאטם בחומר גמיש.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**צנרת פוליאתילן (פקס) – קיפול או כיפוף חד** — צנרת PEX מקופלת או מכופפת בזווית חדה מדי, מצמצמת את חתך הזרימה ועלולה להיסדק לאורך זמן.. המלצה: להחליף את קטע הצנרת המקופל, להתקין מחדש עם רדיוס כיפוף תקני, או להשתמש בפיטינג זווית.. עלות משוערת: ₪200-₪800 (ליחידה)', '**צנרת פוליאתילן (פקס) – קיפול או כיפוף חד** — צנרת PEX מקופלת או מכופפת בזווית חדה מדי, מצמצמת את חתך הזרימה ועלולה להיסדק לאורך זמן.. המלצה: להחליף את קטע הצנרת המקופל, להתקין מחדש עם רדיוס כיפוף תקני, או להשתמש בפיטינג זווית.. עלות משוערת: ₪200-₪800 (ליחידה)', 'ת"י 1205 חלק 1 — רדיוס כיפוף מינימלי של צנרת PEX: 8 פעמים קוטר הצנרת. אין לקפל או לכופף בזווית חדה.', 'ת"י 1205 חלק 1 — רדיוס כיפוף מינימלי של צנרת PEX: 8 פעמים קוטר הצנרת. אין לקפל או לכופף בזווית חדה.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**ערבוב חומרי צנרת לא תואמים (קורוזיה גלוונית)** — חיבור ישיר בין צנרת נחושת לצנרת פלדה מגולוונת ללא מפריד דיאלקטרי, גורם לקורוזיה גלוונית ולנזילות.. המלצה: להתקין מפריד דיאלקטרי (dielectric union) בין חומרי הצנרת השונים.. עלות משוערת: ₪150-₪500 (ליחידה)', '**ערבוב חומרי צנרת לא תואמים (קורוזיה גלוונית)** — חיבור ישיר בין צנרת נחושת לצנרת פלדה מגולוונת ללא מפריד דיאלקטרי, גורם לקורוזיה גלוונית ולנזילות.. המלצה: להתקין מפריד דיאלקטרי (dielectric union) בין חומרי הצנרת השונים.. עלות משוערת: ₪150-₪500 (ליחידה)', 'ת"י 1205 חלק 1 — אין לחבר ישירות בין מתכות שונות ללא מפריד דיאלקטרי או אבזר מתאים למניעת קורוזיה גלוונית.', 'ת"י 1205 חלק 1 — אין לחבר ישירות בין מתכות שונות ללא מפריד דיאלקטרי או אבזר מתאים למניעת קורוזיה גלוונית.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**פילטר (מסנן) מים ראשי – חסר או לא תקין** — לא הותקן מסנן מים ראשי בכניסת המים לדירה, או שהמסנן סתום ודורש ניקוי/החלפה.. המלצה: להתקין מסנן מים ראשי (פילטר Y או פילטר רשת) בכניסת המים לדירה, לאחר מד המים.. עלות משוערת: ₪150-₪500 (ליחידה)', '**פילטר (מסנן) מים ראשי – חסר או לא תקין** — לא הותקן מסנן מים ראשי בכניסת המים לדירה, או שהמסנן סתום ודורש ניקוי/החלפה.. המלצה: להתקין מסנן מים ראשי (פילטר Y או פילטר רשת) בכניסת המים לדירה, לאחר מד המים.. עלות משוערת: ₪150-₪500 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**מוביל מים גמיש (צינור חיבור) פגום או מנופח** — צינור חיבור גמיש (flexible hose) לברז, אסלה, או מכשיר חשמלי מנופח, סדוק, או חלוד בחיבורים. סיכון גבוה להצפה.. המלצה: להחליף מיידית את המוביל הגמיש הפגום בצינור חדש תקני (נירוסטה קלועה), ולבדוק תקינות כל המובילים הגמישים בדירה.. עלות משוערת: ₪80-₪250 (ליחידה)', '**מוביל מים גמיש (צינור חיבור) פגום או מנופח** — צינור חיבור גמיש (flexible hose) לברז, אסלה, או מכשיר חשמלי מנופח, סדוק, או חלוד בחיבורים. סיכון גבוה להצפה.. המלצה: להחליף מיידית את המוביל הגמיש הפגום בצינור חדש תקני (נירוסטה קלועה), ולבדוק תקינות כל המובילים הגמישים בדירה.. עלות משוערת: ₪80-₪250 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**וונטוזה (שסתום שחרור אוויר) חסרה או לא תקינה** — וונטוזה (שסתום שחרור אוויר) חסרה בנקודה הגבוהה ביותר של מערכת המים, גורם לכיסי אוויר ולהפרעה בזרימה.. המלצה: להתקין וונטוזה אוטומטית בנקודה הגבוהה ביותר של מערכת הצנרת.. עלות משוערת: ₪100-₪350 (ליחידה)', '**וונטוזה (שסתום שחרור אוויר) חסרה או לא תקינה** — וונטוזה (שסתום שחרור אוויר) חסרה בנקודה הגבוהה ביותר של מערכת המים, גורם לכיסי אוויר ולהפרעה בזרימה.. המלצה: להתקין וונטוזה אוטומטית בנקודה הגבוהה ביותר של מערכת הצנרת.. עלות משוערת: ₪100-₪350 (ליחידה)', 'ת"י 1205 חלק 1 — יש להתקין שסתום שחרור אוויר (וונטוזה) בנקודות הגבוהות של מערכת אספקת המים.', 'ת"י 1205 חלק 1 — יש להתקין שסתום שחרור אוויר (וונטוזה) בנקודות הגבוהות של מערכת אספקת המים.', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**נזילה מצנרת מים** — נזילת מים מצנרת גלויה או סמויה. עלולה לגרום לנזקי רטיבות.. המלצה: איתור מקור הנזילה, תיקון או החלפת הצנרת הפגומה. עלות משוערת: ₪300-₪1200 (ליחידה)', '**נזילה מצנרת מים** — נזילת מים מצנרת גלויה או סמויה. עלולה לגרום לנזקי רטיבות.. המלצה: איתור מקור הנזילה, תיקון או החלפת הצנרת הפגומה. עלות משוערת: ₪300-₪1200 (ליחידה)', 'ת"י 1205 — מערכת אינסטלציה חייבת להיות אטומה לחלוטין', 'ת"י 1205 — מערכת אינסטלציה חייבת להיות אטומה לחלוטין', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — מים', '**ברז מטפטף / לא אוטם** — ברז שמטפטף גם כשסגור, או שלא אוטם כראוי.. המלצה: החלפת אטם / קרמי / ברז שלם לפי הצורך. עלות משוערת: ₪100-₪500 (ליחידה)', '**ברז מטפטף / לא אוטם** — ברז שמטפטף גם כשסגור, או שלא אוטם כראוי.. המלצה: החלפת אטם / קרמי / ברז שלם לפי הצורך. עלות משוערת: ₪100-₪500 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**סיפון חסר או לא תקין – ריח ביוב** — סיפון (מחסום ריח) חסר, לא מותקן, פגום או יבש, וגורם לחדירת ריחות ביוב לתוך הדירה דרך נקודת הניקוז.. המלצה: להתקין סיפון תקני עם עומק מחסום מים של 50 מ"מ לפחות, לוודא אטימות כל החיבורים.. עלות משוערת: ₪150-₪500 (ליחידה)', '**סיפון חסר או לא תקין – ריח ביוב** — סיפון (מחסום ריח) חסר, לא מותקן, פגום או יבש, וגורם לחדירת ריחות ביוב לתוך הדירה דרך נקודת הניקוז.. המלצה: להתקין סיפון תקני עם עומק מחסום מים של 50 מ"מ לפחות, לוודא אטימות כל החיבורים.. עלות משוערת: ₪150-₪500 (ליחידה)', 'ת"י 1205 חלק 2 — כל כלי סניטרי יחובר לסיפון עם מחסום מים בעומק מינימלי של 50 מ"מ. אין לחבר כלי סניטרי לביוב ללא סיפון.', 'ת"י 1205 חלק 2 — כל כלי סניטרי יחובר לסיפון עם מחסום מים בעומק מינימלי של 50 מ"מ. אין לחבר כלי סניטרי לביוב ללא סיפון.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**סיפון רצפתי חסום או ניקוז איטי** — סיפון רצפתי (במקלחת, במרפסת) חסום חלקית או מלא, גורם להצטברות מים על הרצפה ולניקוז איטי.. המלצה: לנקות את הסיפון מפסולת, לפתוח חסימות בצנרת, לוודא שיפוע תקין של הרצפה לכיוון הסיפון.. עלות משוערת: ₪100-₪400 (ליחידה)', '**סיפון רצפתי חסום או ניקוז איטי** — סיפון רצפתי (במקלחת, במרפסת) חסום חלקית או מלא, גורם להצטברות מים על הרצפה ולניקוז איטי.. המלצה: לנקות את הסיפון מפסולת, לפתוח חסימות בצנרת, לוודא שיפוע תקין של הרצפה לכיוון הסיפון.. עלות משוערת: ₪100-₪400 (ליחידה)', 'ת"י 1205 חלק 2 — סיפון רצפתי יאפשר ניקוז חופשי של מים, רשת הסיפון תהיה ניתנת להסרה לצורך ניקוי.', 'ת"י 1205 חלק 2 — סיפון רצפתי יאפשר ניקוז חופשי של מים, רשת הסיפון תהיה ניתנת להסרה לצורך ניקוי.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**שיפוע ניקוז לא תקין – מים עומדים על רצפה** — רצפת חדר רחצה או מקלחת ללא שיפוע מספיק לכיוון הסיפון, גורם להצטברות מים (שלוליות) על הרצפה.. המלצה: לבצע יציקת שיפוע מתקנת על הרצפה הקיימת וריצוף מחדש, או התקנת ערוץ ניקוז ליניארי.. עלות משוערת: ₪2000-₪5000 (ליחידה)', '**שיפוע ניקוז לא תקין – מים עומדים על רצפה** — רצפת חדר רחצה או מקלחת ללא שיפוע מספיק לכיוון הסיפון, גורם להצטברות מים (שלוליות) על הרצפה.. המלצה: לבצע יציקת שיפוע מתקנת על הרצפה הקיימת וריצוף מחדש, או התקנת ערוץ ניקוז ליניארי.. עלות משוערת: ₪2000-₪5000 (ליחידה)', 'ת"י 1205 חלק 2 — רצפה רטובה (חדר מקלחת) חייבת בשיפוע מינימלי של 1.5% לכיוון נקודת הניקוז.', 'ת"י 1205 חלק 2 — רצפה רטובה (חדר מקלחת) חייבת בשיפוע מינימלי של 1.5% לכיוון נקודת הניקוז.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**צנרת ביוב ללא שיפוע תקני** — צנרת הביוב מותקנת ללא שיפוע מספיק או עם שיפוע הפוך (counter-slope), גורם לחסימות חוזרות ולעליית מי ביוב.. המלצה: לפרק את קטע הצנרת הבעייתי, להתקין מחדש בשיפוע הנדרש, ולבצע בדיקת זרימה.. עלות משוערת: ₪800-₪3000 (למ"א)', '**צנרת ביוב ללא שיפוע תקני** — צנרת הביוב מותקנת ללא שיפוע מספיק או עם שיפוע הפוך (counter-slope), גורם לחסימות חוזרות ולעליית מי ביוב.. המלצה: לפרק את קטע הצנרת הבעייתי, להתקין מחדש בשיפוע הנדרש, ולבצע בדיקת זרימה.. עלות משוערת: ₪800-₪3000 (למ"א)', 'ת"י 1205 חלק 2 — צנרת ביוב אופקית בקוטר עד 100 מ"מ: שיפוע מינימלי 2%. קוטר מעל 100 מ"מ: שיפוע מינימלי 1%.', 'ת"י 1205 חלק 2 — צנרת ביוב אופקית בקוטר עד 100 מ"מ: שיפוע מינימלי 2%. קוטר מעל 100 מ"מ: שיפוע מינימלי 1%.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**חסימה בצנרת ביוב ראשית** — חסימה בצנרת ביוב ראשית של הדירה, גורמת לעליית מי שפכים בכלים סניטריים או הצפה.. המלצה: לבצע שטיפת לחץ (ג''טינג) לצנרת הביוב, לבדוק במצלמה אנדוסקופית, לתקן או להחליף קטע פגום.. עלות משוערת: ₪300-₪1500 (ליחידה)', '**חסימה בצנרת ביוב ראשית** — חסימה בצנרת ביוב ראשית של הדירה, גורמת לעליית מי שפכים בכלים סניטריים או הצפה.. המלצה: לבצע שטיפת לחץ (ג''טינג) לצנרת הביוב, לבדוק במצלמה אנדוסקופית, לתקן או להחליף קטע פגום.. עלות משוערת: ₪300-₪1500 (ליחידה)', 'ת"י 1205 חלק 2 — מערכת הביוב חייבת לאפשר זרימה חופשית. יש להתקין פקקי ניקוי בנקודות נגישות.', 'ת"י 1205 חלק 2 — מערכת הביוב חייבת לאפשר זרימה חופשית. יש להתקין פקקי ניקוי בנקודות נגישות.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**היעדר פקק ניקוי בצנרת ביוב** — לא הותקנו פקקי ניקוי (access points) בצנרת הביוב במקומות הנדרשים, מה שמקשה על טיפול בחסימות עתידיות.. המלצה: להתקין פקקי ניקוי בנקודות הנדרשות בהתאם לתקן, במקומות נגישים.. עלות משוערת: ₪200-₪600 (ליחידה)', '**היעדר פקק ניקוי בצנרת ביוב** — לא הותקנו פקקי ניקוי (access points) בצנרת הביוב במקומות הנדרשים, מה שמקשה על טיפול בחסימות עתידיות.. המלצה: להתקין פקקי ניקוי בנקודות הנדרשות בהתאם לתקן, במקומות נגישים.. עלות משוערת: ₪200-₪600 (ליחידה)', 'ת"י 1205 חלק 2 — יש להתקין פקקי ניקוי בכל שינוי כיוון של צנרת הביוב, בסוף כל קו אופקי, ובמרחק מרבי של 15 מ'' בין פקק לפקק.', 'ת"י 1205 חלק 2 — יש להתקין פקקי ניקוי בכל שינוי כיוון של צנרת הביוב, בסוף כל קו אופקי, ובמרחק מרבי של 15 מ'' בין פקק לפקק.', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'אינסטלציה — ביוב וניקוז', '**צנרת PVC ביוב – חיבור לא תקין** — חיבור לקוי בצנרת PVC ביוב – שימוש בדבק לא מתאים, חיבור לא מלא, או חוסר אטימות בנקודות חיבור.. המלצה: לפרק את החיבור הלקוי, לנקות את המשטחים, להדביק מחדש בדבק PVC מתאים, ולבצע בדיקת אטימות.. עלות משוערת: ₪200-₪800 (ליחידה)', '**צנרת PVC ביוב – חיבור לא תקין** — חיבור לקוי בצנרת PVC ביוב – שימוש בדבק לא מתאים, חיבור לא מלא, או חוסר אטימות בנקודות חיבור.. המלצה: לפרק את החיבור הלקוי, לנקות את המשטחים, להדביק מחדש בדבק PVC מתאים, ולבצע בדיקת אטימות.. עלות משוערת: ₪200-₪800 (ליחידה)', 'ת"י 1205 חלק 2 — חיבורי צנרת ביוב PVC יבוצעו בדבק מתאים לסוג הצנרת, עם חדירה מלאה של הצנרת לתוך האבזר.', 'ת"י 1205 חלק 2 — חיבורי צנרת ביוב PVC יבוצעו בדבק מתאים לסוג הצנרת, עם חדירה מלאה של הצנרת לתוך האבזר.', true, 'medium');
